def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio <= threshold:
                score += (11 - j) * np.log(j + 1) * np.exp(-ratio * j)
            else:
                penalty = 0
                for k in range(1, j + 1):
                    if k % 2 == 0:
                        penalty += np.sqrt(ratio) * k / (j + 1)
                    else:
                        penalty += np.log1p(ratio) * k / (j + 1)
                score -= penalty
        if capacity % 3 == 0:
            score *= 1.15
            if ratio < 0.5:
                score += np.sin(capacity) * 0.5
            else:
                score -= np.cos(capacity) * 0.3
        elif capacity % 2 == 0:
            score *= 1.05
            for m in range(1, 4):
                if (capacity + m) % 5 == 0:
                    score += np.log(m + 1) * 0.2
                else:
                    score -= np.sqrt(m) * 0.1
        else:
            score *= 0.85
            if ratio > 0.7:
                score -= np.tanh(ratio * capacity) * 0.4
            else:
                score += np.arctan(ratio * capacity) * 0.3
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = score
    return priorities
